function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const incoming = $json || {};
const now = new Date().toISOString();
const baseCtx = (incoming.ctx && typeof incoming.ctx === 'object') ? incoming.ctx : {};

const prompt = String(incoming.prompt || '').trim();
const variant = String(incoming.render_variant || '').trim();
if (!prompt || prompt.length < 40) throw new Error('TVPX__30A: prompt missing or too short.');
if (!variant) throw new Error('TVPX__30A: render_variant missing.');

const traceId = String(baseCtx.trace_id || '').trim() || \`tvpx_\${fnv1a(JSON.stringify(incoming).slice(0, 5000) + '::' + now)}\`;
const assetFamilyId = String(baseCtx.asset_family_id || incoming.asset_family_id || \`tvpxfam_\${fnv1a(traceId + '::assetfam')}\`).trim();

const jobId = \`tvpx_job_\${fnv1a([
  traceId,
  incoming.scene_seed_id,
  incoming.scene_blueprint_id,
  incoming.blueprint_label,
  variant,
  prompt,
].join('::'))}\`;

const ctx = {
  project_ns: 'TVPX',
  brand_name: 'The Velvet Paradox',
  trace_id: traceId,
  asset_family_id: assetFamilyId,
  trigger_mode: baseCtx.trigger_mode || incoming.trigger_mode || 'internal',
  route_mode: 'fal_submit_poll',
  received_at: now,
  fal_api_key: String(baseCtx.fal_api_key || incoming.fal_api_key || '').trim(),
  fal_endpoint_url: String(baseCtx.fal_endpoint_url || incoming.fal_endpoint_url || '').trim(),
  image_size: String(baseCtx.image_size || incoming.provider_controls?.image_size || '1024x1536'),
  output_format: String(baseCtx.output_format || incoming.provider_controls?.output_format || 'png'),
  background: String(baseCtx.background || incoming.provider_controls?.background || 'opaque'),
  quality: String(baseCtx.quality || incoming.provider_controls?.quality || 'high'),
  poll_max: Number(baseCtx.poll_max || incoming.poll_max || 24),
};

return [{
  json: {
    ctx,
    scene_seed_row: incoming.scene_seed_row || null,
    archetype_row: incoming.archetype_row || null,
    blueprint: incoming.blueprint || null,
    job: {
      job_id: jobId,
      concept_id: String(incoming.concept_id || incoming.scene_seed_id || '').trim(),
      scene_seed_id: String(incoming.scene_seed_id || '').trim(),
      scene_blueprint_id: String(incoming.scene_blueprint_id || '').trim(),
      archetype_id: String(incoming.archetype_id || '').trim(),
      blueprint_label: String(incoming.blueprint_label || '').trim(),
      render_variant: variant,
      provider_name: 'fal',
      candidate_index: null,
      request: {
        prompt,
        image_size: ctx.image_size,
        background: ctx.background,
        quality: ctx.quality,
        output_format: ctx.output_format,
        num_images: Number(incoming.provider_controls?.num_images || 1),
        sync_mode: false,
      },
      prompt_raw: prompt,
      negative_prompt_raw: String(incoming.negative_prompt || '').trim(),
      state: 'queued',
      created_at: now,
      updated_at: now,
    },
  },
}];

/** Pass Envelope: re-output envelope so Fal Submit Render receives ctx/job (DataTable returns ledger row). */
const envelope = $items('Initialize Envelope')[0]?.json;
if (!envelope?.ctx || !envelope?.job) throw new Error('TVPX__30A: Pass Envelope could not read envelope from Initialize Envelope.');
return [{ json: envelope }];

