/**
 * Normalize Submit Response
 * Expected (typical fal queue): { request_id / id?, status_url, response_url }
 * We store status_url + response_url and move into polling.
 */

const base = $items('Initialize Envelope')[0].json;
const ctx = base.ctx;
const job = base.job;

const resp = $json || {};
const body = resp.body ?? resp.data ?? resp;

const statusUrl = String(body.status_url || body.statusUrl || body.data?.status_url || '').trim();
const responseUrl = String(body.response_url || body.responseUrl || body.data?.response_url || '').trim();
const providerJobId = String(body.request_id || body.id || body.requestId || '').trim();

if (!statusUrl && !responseUrl) {
  // Some fal endpoints may return only status_url; accept either, but require at least one.
  throw new Error('Fal submit did not return status_url or response_url. Check endpoint and auth.');
}

return [{
  json: {
    ctx,
    job: {
      ...job,
      provider_job_id: providerJobId,
      status_url: statusUrl,
      response_url: responseUrl,
      state: 'queued'
    }
  }
}];

/**
 * Initialize Poll State
 * Rehydrate from normalized submit payload so Data Table side effects cannot strip context.
 */
const normalized = $items('Normalize Submit Response')[0]?.json || {};
const j = ($json && $json.ctx && $json.job) ? $json : normalized;
const ctx = j.ctx;
const job = j.job;

if (!ctx || !job) {
  throw new Error('TVPX__30A: missing ctx/job while initializing poll state.');
}

return [{
  json: {
    ctx,
    job,
    poll: {
      tries: 0,
      max: Number(ctx.poll_max || 24),
      interval_seconds: Number(ctx.poll_interval_seconds || 8)
    }
  }
}];

function extractImageUrls(body) {
  const urls = [];
  const add = (value) => {
    const text = String(value || '').trim();
    if (text && !urls.includes(text)) urls.push(text);
  };
  const walkArray = (arr) => {
    if (!Array.isArray(arr)) return;
    for (const item of arr) {
      if (typeof item === 'string') add(item);
      else if (item && typeof item === 'object') add(item.url || item.href || item.image_url);
    }
  };
  walkArray(body.images);
  walkArray(body?.data?.images);
  walkArray(body?.result?.images);
  walkArray(body?.output?.images);
  if (body.image) add(body.image?.url || body.image);
  if (body?.data?.image) add(body.data.image?.url || body.data.image);
  return urls;
}

const base = $items('Initialize Poll State')[0].json;
const ctx = base.ctx;
const job = base.job;
const poll = base.poll;
const sceneSeedRow = base.scene_seed_row || null;
const archetypeRow = base.archetype_row || null;
const blueprint = base.blueprint || null;

const resp = $json || {};
const body = resp.body ?? resp.data ?? resp;
const statusRaw = String(body.status || body.data?.status || '').trim();

return [{
  json: {
    ctx,
    scene_seed_row: sceneSeedRow,
    archetype_row: archetypeRow,
    blueprint,
    job: {
      ...job,
      polled_status: statusRaw ? statusRaw.toUpperCase() : '',
      provider_image_urls: extractImageUrls(body),
      error_text: String(body.error || body.message || body.data?.error || '').trim(),
    },
    poll,
  },
}];

function extractImageUrls(body) {
  const urls = [];
  const add = (value) => {
    const text = String(value || '').trim();
    if (text && !urls.includes(text)) urls.push(text);
  };
  const walkArray = (arr) => {
    if (!Array.isArray(arr)) return;
    for (const item of arr) {
      if (typeof item === 'string') add(item);
      else if (item && typeof item === 'object') add(item.url || item.href || item.image_url);
    }
  };
  walkArray(body.images);
  walkArray(body?.data?.images);
  walkArray(body?.result?.images);
  walkArray(body?.output?.images);
  if (body.image) add(body.image?.url || body.image);
  return urls;
}

const envelope = $items('Normalize Poll Response')[0]?.json;
if (!envelope?.ctx || !envelope?.job) throw new Error('TVPX__30A: missing envelope in Merge Result Into Job.');

const resp = $json || {};
const body = resp.body ?? resp.data ?? resp;
const imageUrls = extractImageUrls(body);

return [{
  json: {
    ctx: envelope.ctx,
    scene_seed_row: envelope.scene_seed_row || null,
    archetype_row: envelope.archetype_row || null,
    blueprint: envelope.blueprint || null,
    job: {
      ...envelope.job,
      provider_image_urls: imageUrls.length ? imageUrls : (envelope.job.provider_image_urls || []),
    },
  },
}];

/**
 * Increment Poll
 * Loops until completed/failed/timeout.
 */

const ctx = $json.ctx;
const job = $json.job;
const poll = $json.poll;

poll.tries = Number(poll.tries || 0) + 1;

const max = Number(poll.max || 24);
const timedOut = poll.tries >= max;

return [{
  json: {
    ctx,
    job,
    poll,
    timed_out: timedOut
  }
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const ctx = $json.ctx;
const job = $json.job;
const sceneSeedRow = $json.scene_seed_row || null;
const archetypeRow = $json.archetype_row || null;
const blueprint = $json.blueprint || null;
const urls = Array.isArray(job.provider_image_urls) ? job.provider_image_urls.filter(Boolean) : [];

if (!urls.length) {
  throw new Error('TVPX__30A: completed job but no image URLs were found.');
}

return urls.map((url, idx) => {
  const renderCandidateId = \`tvpx_rc_\${fnv1a([job.job_id, idx + 1, url].join('::'))}\`;
  return {
    json: {
      ctx,
      concept_id: String(job.concept_id || job.scene_seed_id || '').trim(),
      status: 'completed',
      job_id: job.job_id,
      render_candidate_id: renderCandidateId,
      scene_seed_id: job.scene_seed_id,
      scene_blueprint_id: job.scene_blueprint_id,
      scene_seed_row: sceneSeedRow,
      archetype_id: job.archetype_id,
      archetype_row: archetypeRow,
      blueprint_label: job.blueprint_label,
      blueprint,
      candidate_index: idx + 1,
      render_variant: job.render_variant,
      provider_name: job.provider_name,
      provider_job_id: job.provider_job_id,
      image_url: String(url).trim(),
      prompt_final: String(job.request?.prompt || '').trim(),
      negative_prompt_raw: String(job.negative_prompt_raw || '').trim(),
      image_size: String(job.request?.image_size || ''),
      background: String(job.request?.background || ''),
      quality: String(job.request?.quality || ''),
      output_format: String(job.request?.output_format || ''),
      completed_at: new Date().toISOString(),
    },
  };
});

/** Finalize Failure */
const ctx = $json.ctx;
const job = $json.job;
const err = String(job.error_text || 'Fal job failed.').trim();
return [{
  json: {
    ctx,
    job_id: job.job_id,
    concept_id: job.concept_id,
    render_variant: job.render_variant,
    provider_name: job.provider_name,
    provider_job_id: job.provider_job_id,
    status_url: job.status_url,
    response_url: job.response_url,
    prompt_raw: String(job.prompt_raw || '').trim(),
    negative_prompt_raw: String(job.negative_prompt_raw || '').trim(),
    prompt_final: String(job.request?.prompt || '').trim(),
    image_size: String(job.provider_controls?.image_size || job.request?.image_size || ''),
    background: String(job.provider_controls?.background || job.request?.background || ''),
    quality: String(job.provider_controls?.quality || job.request?.quality || ''),
    output_format: String(job.provider_controls?.output_format || job.request?.output_format || ''),
    concept_snapshot: job.concept_snapshot || null,
    error_text: err,
    failed_at: new Date().toISOString()
  }
}];

/** Finalize Timed Out */
const ctx = $json.ctx;
const job = $json.job;
const poll = $json.poll;
return [{
  json: {
    ctx,
    job_id: job.job_id,
    concept_id: job.concept_id,
    render_variant: job.render_variant,
    provider_name: job.provider_name,
    provider_job_id: job.provider_job_id,
    status_url: job.status_url,
    response_url: job.response_url,
    prompt_raw: String(job.prompt_raw || '').trim(),
    negative_prompt_raw: String(job.negative_prompt_raw || '').trim(),
    prompt_final: String(job.request?.prompt || '').trim(),
    image_size: String(job.provider_controls?.image_size || job.request?.image_size || ''),
    background: String(job.provider_controls?.background || job.request?.background || ''),
    quality: String(job.provider_controls?.quality || job.request?.quality || ''),
    output_format: String(job.provider_controls?.output_format || job.request?.output_format || ''),
    concept_snapshot: job.concept_snapshot || null,
    error_text: `Timed out after ${poll.tries} polls.`,
    poll_count: Number(poll.tries || 0),
    failed_at: new Date().toISOString()
  }
}];

const base = $items('Finalize Timed Out')[0]?.json;
if (!base) throw new Error('TVPX__30A: missing Finalize Timed Out payload.');

return [{
  json: {
    ...base,
    status: 'timed_out'
  }
}];

const base = $items('Finalize Failed')[0]?.json;
if (!base) throw new Error('TVPX__30A: missing Finalize Failed payload.');

return [{
  json: {
    ...base,
    status: 'failed'
  }
}];
